mapper.update:
UPDATE logs
SET title = #{title}, content = #{content}, log_date = #{logDate}
WHERE id = #{id} AND user_id = #{userId};

mapper.select:
SELECT l.user_id, l.id AS log_id, l.user_id AS log_user_id, l.title, l.log_date,
t.id AS tag_id, t.user_id AS tag_user_id, t.name AS tag_name, t.color AS tag_color
FROM logs l LEFT JOIN log_tags lt ON l.id = lt.log_id LEFT JOIN tags t ON lt.tag_id = t.id WHERE l.user_id = #{userId} ORDER BY l.log_date DESC, l.created_at DESC;

SELECT l.user_id, l.id AS log_id, l.user_id AS log_user_id, l.title, l.content, l.log_date,
t.id AS tag_id, t.user_id AS tag_user_id, t.name AS tag_name, t.color AS tag_color
FROM logs l LEFT JOIN log_tags lt ON l.id = lt.log_id LEFT JOIN tags t ON lt.tag_id = t.id WHERE l.user_id = #{userId} AND l.id = #{logId}
